def longest_run_char(s):
    if not s:
        return ''

    max_length = 1
    current_char = s[0]
    current_length = 1

    for i in range(1, len(s)):
        if s[i] == current_char:
            current_length += 1
        else:
            if current_length >= max_length:
                max_length = current_length
                longest_char = current_char
            current_char = s[i]
            current_length = 1

    # Final check for the last character(s) sequence
    if current_length >= max_length:
        longest_char = current_char

    return longest_char
